public static ETGProformaInvoiceDP construct()
{
    ETGProformaInvoiceDP  dataProvider;

    dataProvider = new ETGProformaInvoiceDP();

    return dataProvider;
}

public ETGProformaInvoiceTmp processReport (ETGProformaInvoiceContract _contract)
{
    SalesAgreementId            salesAgreementId;
    SalesAgreementHeader        salesAgreementHeader;

    salesAgreementId        =   _contract.parmSalesAgreementId();
    salesAgreementHeader    =   SalesAgreementHeader::findAgreementId(salesAgreementId);

    proformaInvoiceTmp.SalesAgreementId            =   salesAgreementHeader.SalesNumberSequence;
    proformaInvoiceTmp.CustAccount                 =   salesAgreementHeader.CustAccount;
    proformaInvoiceTmp.SalesAgreementHeaderRecId   =   salesAgreementHeader.RecId;

    ttsbegin;
    proformaInvoiceTmp.insert();
    ttscommit;

    // Select all rows from tmp table and return
    select proformaInvoiceTmp;
    return proformaInvoiceTmp;
}
